javascript: const buttons = document.querySelectorAll('button');

const lastButton = buttons[buttons.length - 1];
const firstButton = buttons[0];

let currentButtonIndex = 0;

function getNextButtonIndex(currentIndex) {
  return (currentIndex + 1) % buttons.length;
}

function getPreviousButtonIndex(currentIndex) {
  return (currentIndex - 1 + buttons.length) % buttons.length;
}

document.addEventListener('keydown', (event) => {
  if (event.key === 'Tab') {
    if (event.shiftKey) {
      currentButtonIndex = getPreviousButtonIndex(currentButtonIndex);
    } else {
      currentButtonIndex = getNextButtonIndex(currentButtonIndex);
    }
    buttons[currentButtonIndex].focus();
  }
});

firstButton.focus();
